import{_ as o,o as t,c as i,ag as r}from"./chunks/framework.DfsMvb5-.js";const g=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),a={name:"changelog.md"};function n(l,e,s,d,c,u){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">â€‹</a></h1><p>All notable changes to this project will be documented in this file.</p><p>The format is based on <a href="https://keepachangelog.com/en/1.0.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>, and this project adheres to <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">Semantic Versioning</a>.</p><h2 id="unreleased" tabindex="-1">[Unreleased] <a class="header-anchor" href="#unreleased" aria-label="Permalink to &quot;[Unreleased]&quot;">â€‹</a></h2><h2 id="_0-2-2-2026-04-26" tabindex="-1">[0.2.2] - 2026-04-26 <a class="header-anchor" href="#_0-2-2-2026-04-26" aria-label="Permalink to &quot;[0.2.2] - 2026-04-26&quot;">â€‹</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">â€‹</a></h3><ul><li><strong><code>postertime</code> Attribute</strong>: Generate a native-resolution poster from any timestamp without an explicit <code>poster</code> URL. Accepts <code>&quot;10%&quot;</code>, <code>&quot;5&quot;</code>, <code>&quot;1:30&quot;</code>, or <code>&quot;0:01:30&quot;</code>. Uses an isolated thumbnail pipeline (WASM + <code>ThumbnailBindings</code>), respects rotation metadata, and is race-guarded so in-flight generators can&#39;t paint stale frames after a <code>src</code> change.</li><li><strong><code>dispose()</code> Method</strong>: Tears down the internal player and resets transient UI (subtitles, timeline, time, title, generated poster) back to the no-source state. Called automatically on every <code>src</code> change so playlist-style flows never leak state between sources. Safe to call when nothing is loaded.</li><li><strong><code>playing</code> Getter</strong>: Read-only boolean that&#39;s <code>true</code> only while the player is actively playing â€” distinguishes it from <code>ready</code>, <code>loading</code>, <code>seeking</code>, and <code>buffering</code> states (precise inverse of <code>paused</code>).</li><li><strong><code>MoviElement.cleanVideoTitle(filename)</code> Static</strong>: Utility exposed for playlist UIs to derive the same cleaned title the player uses internally â€” useful for computing the resume localStorage key (<code>movi-resume:&lt;cleanVideoTitle(name)&gt;</code>).</li><li><strong>Folder Playlist (web demo app)</strong>: Sidebar/below-player playlist via File System Access API (with <code>webkitdirectory</code> fallback). YouTube-style items with thumbnail, duration, HDR chip, codec/quality/size meta, and watched-progress bar. Lazy thumbnail generation, natural-sort, autoplay-next toggle, drag-and-drop multi-file support.</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">â€‹</a></h3><ul><li><strong><code>play()</code> Semantics</strong>: Now queues a play intent during <code>isLoading</code> and flushes it from <code>initializePlayer()</code>&#39;s finally block â€” matches <code>HTMLMediaElement</code> behavior. Previously bailed silently when called during load.</li><li><strong>Software Decoder Fallback Per-Source</strong>: Choosing &quot;Try software&quot; no longer sticks across <code>src</code> changes. The next video gets a fresh hardware-decode attempt; the <code>sw</code> attribute is cleared on dispose.</li><li><strong>Encrypted Playback Protocol</strong>: <code>EncryptedHttpSource</code> rewritten â€” block prefetch high-water/low-water tuning, concurrent-stream cap, <code>getPosition()</code> reports the real read cursor, and parent position field is kept in sync so buffer math stays honest. Encrypted-server ported to match the new protocol.</li><li><strong>Buffer Tuning</strong>: Runtime tuning of prefetch high-water, refill threshold, and block cache cap via the existing <code>buffersize</code> attribute. README/docs corrected to clarify the value is in <strong>megabytes</strong> (not seconds) and applies to both HTTP and encrypted sources.</li><li><strong>Production Bundles</strong>: Re-enabled terser <code>drop_console</code> and <code>drop_debugger</code> so release builds ship without dev-only logging.</li><li><strong>Build Stability</strong>: <code>app:release</code> script ties build + R2 upload + worker deploy into a single command. Build version cache-bust scoped to the quoted <code>__BUILD_VERSION__</code> literal so unrelated lines aren&#39;t rewritten.</li></ul><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">â€‹</a></h3><ul><li><strong>Post-Seek A/V Sync</strong>: Cap the post-seek audio gap at 200ms â€” when the first video frame after a seek arrives late (sparse keyframes / slow HEVC+HDR decoders), sync the clock to video time and drop stale audio instead of syncing to the earliest audio packet. Small gaps still prefer audio for continuity.</li><li><strong>Pre-Play Seek Position</strong>: Scrubbing the timeline before pressing play no longer resets to 0 â€” the first-play poster-seek now reads <code>clock.getTime()</code> instead of a hardcoded start time. Pipeline is flushed on user seek so prebuffered start audio doesn&#39;t briefly play before jumping to the target.</li><li><strong>Fully-Cached Buffered Duration</strong>: Buffered range now reports the full media duration when the file is fully cached, instead of stopping at the last network read.</li><li><strong>Buffer Indicator Race</strong>: Collapsed the seek-race scan sweep that could draw a phantom buffered range mid-seek.</li><li><strong>Encrypted Thumbnails</strong>: Share the main source for thumbnail reads instead of opening a parallel session â€” cuts redundant token churn. Concurrent stream cap prevents seek-storm thrash. Hardened thumbnail read failures (no more fragile retry/cooldown loop).</li><li><strong>Worker <code>/proxy</code> Empty 206</strong>: Retry empty 206 responses from upstream before streaming back, so transient origin hiccups don&#39;t surface as broken playback.</li><li><strong>Worker Probe Failures</strong>: Transient probe errors no longer get misreported as <code>415 Unsupported Media Type</code>.</li><li><strong>TMDb Title Parser</strong>: Detect TV shows when the episode title trails the <code>SxxExx</code> code (e.g., <code>Show.S05E01.Title</code>).</li></ul><h3 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">â€‹</a></h3><ul><li><strong>Worker Referer Allowlist</strong>: <code>/proxy</code> and <code>/eproxy</code> endpoints now gate requests by Referer to block hotlinking from unauthorized origins.</li><li><strong>Worker Magic-Byte Validation</strong>: <code>/proxy</code> responses are validated against expected media magic bytes before being streamed back, mitigating MIME confusion attacks.</li></ul><h2 id="_0-2-1-2026-04-16" tabindex="-1">[0.2.1] - 2026-04-16 <a class="header-anchor" href="#_0-2-1-2026-04-16" aria-label="Permalink to &quot;[0.2.1] - 2026-04-16&quot;">â€‹</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">â€‹</a></h3><ul><li><strong>Persistent Preferences</strong>: <code>stableVolume</code>, <code>ambientMode</code>, and <code>hdr</code> toggles now persist via OPFS alongside <code>volume</code>, <code>muted</code>, and <code>playbackRate</code>. User toggles win over HTML attribute defaults on subsequent loads.</li><li><strong>Split-Source Volume Control</strong>: Volume button now visible when a separate native audio element is loaded, even if the video file has no muxed audio track.</li><li><strong>Smart Title Extraction</strong>: VLC-style filename cleaning strips release tags, codecs, and quality markers from tab titles. <code>Content-Disposition</code> filename used when the server provides one.</li><li><strong>Chrome Extension</strong>: Local file playback via popup file picker, drag-and-drop onto the player page, and a redesigned popup layout.</li></ul><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">â€‹</a></h3><ul><li><strong>Context Menu</strong>: Slide-panel variant now only used on touch devices (<code>pointer: coarse</code>); narrow desktop windows get the regular hover-driven menu.</li><li><strong>Context Menu Scrolling</strong>: Max-height clamped to player height with subtle scrollbar styling so tall menus stay accessible on short players.</li><li><strong>Theme Color Cascade</strong>: <code>themecolor</code> attribute now flows to <code>--movi-primary-light</code> and <code>--movi-primary-dark</code> via <code>color-mix</code>, so active menu items and highlights follow the custom theme.</li><li><strong><code>title</code> Attribute</strong>: No longer triggers the browser&#39;s native tooltip on hover â€” title is rendered only by the in-player overlay.</li><li><strong>Subtitle/Audio Track Menus</strong>: Show language codes alongside track labels for clarity.</li></ul><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">â€‹</a></h3><ul><li><strong>Short Video Stutter</strong>: Prebuffer media before <code>ready</code> so <code>play()</code> doesn&#39;t immediately stall on short clips.</li><li><strong>Background Audio at 50/60 fps</strong>: Skip video decode while hidden so audio keeps flowing on high-fps content.</li><li><strong>Narrow Viewport Controls</strong>: Buttons, gaps, and center play button tightened on viewports â‰¤ 480px to prevent the controls bar from overflowing the player box on iPhone 12 Pro-class widths.</li><li><strong>Empty State Placement</strong>: &quot;No Video&quot; placeholder no longer clips into the controls bar on short/narrow players.</li><li><strong>OSD Speed Icon</strong>: Correct speed icon shown when playback rate changes via hotkeys/context menu.</li></ul><h2 id="_0-2-0-2026-04-09" tabindex="-1">[0.2.0] - 2026-04-09 <a class="header-anchor" href="#_0-2-0-2026-04-09" aria-label="Permalink to &quot;[0.2.0] - 2026-04-09&quot;">â€‹</a></h2><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">â€‹</a></h3><ul><li><strong>Ambient Mode</strong>: Dynamic letterbox glow that samples video colors in real-time. Smooth 60fps color transitions via WebGL clearColor. Toggle with <code>G</code> key or context menu. Works in fullscreen (letterbox) and normal mode (external wrapper). <code>ambientmode</code> attribute.</li><li><strong>Split Source Support</strong>: Separate video, audio, and subtitle file URLs via <code>videosrc</code>, <code>audiosrc</code>, <code>subtitlesrc</code> attributes.</li><li><strong>PGS Image Subtitles</strong>: Bitmap subtitle decoding with zlib decompression support.</li><li><strong>Network Disconnect Recovery</strong>: Intelligent CORS vs transient network failure detection (3-strike threshold). Online-event-aware backoff for instant retry on reconnection. Auto re-seek on recovery. 30s timeout on offline wait.</li><li><strong>Document Picture-in-Picture</strong>: Floating video window with play/pause, seek, mute, progress bar, time display, keyboard shortcuts, and back-to-tab button. Portrait video sizing. Rotation save/restore on PiP enter/exit.</li><li><strong>DRM Support</strong>: <code>drm</code> and <code>licenseurl</code> attributes for HLS streams with Widevine/FairPlay via EME API.</li><li><strong>HLS Quality Menu</strong>: Duplicate resolutions show bitrate (e.g., &quot;1080p Â· 5000 kbps&quot;).</li><li><strong>HLS Nerd Stats</strong>: Video codec, resolution, quality, frame rate, bitrate, buffer, HLS level, bandwidth, live latency, frames decoded/dropped.</li><li><strong>VLC-style Shortcuts</strong>: <code>V</code> subtitles, <code>B</code> audio, <code>+/-</code> speed, <code>L</code> loop, <code>U</code> stable volume, <code>H</code> HDR, <code>P</code> PiP, <code>G</code> ambient, <code>A</code> aspect ratio.</li><li><strong>Aspect Ratio Controls</strong>: <code>A</code> key cycles contain/cover/fill/zoom. Sub-menu with icons in context menu and bottom controls.</li><li><strong>Stable Volume</strong>: DynamicsCompressorNode for loudness normalization. Opt-in via <code>stablevolume</code> attribute.</li><li><strong>Nerd Stats</strong>: Press <code>I</code> for codec, resolution, FPS, decoder type, buffer health, color info, and live network/disk activity graph.</li><li><strong>Timeline</strong>: Press <code>T</code> for auto-generated thumbnail strip with chapter support. Arrow key navigation, click-to-seek.</li><li><strong>Chapter Support</strong>: Extract chapters from video metadata. Chapter markers on progress bar, chapter titles in seek tooltip.</li><li><strong>Video Rotation</strong>: Press <code>R</code> to rotate 90Â°. Metadata rotation auto-applied. Disabled during PiP.</li><li><strong>Keyboard Shortcuts Panel</strong>: Press <code>?</code> to view all shortcuts.</li><li><strong>Resume Playback</strong>: <code>resume</code> attribute saves position to localStorage with resume/start-over dialog.</li><li><strong>Encrypted Playback</strong>: AES-256-GCM chunked encryption with HMAC-SHA256 signed requests.</li><li><strong>Background Audio</strong>: Video keeps playing audio when tab is in background via Web Worker timer fallback.</li><li><strong>Chrome Extension</strong>: Popup with &quot;Paste &amp; Play&quot; and &quot;Play from Computer&quot;, context menu on video links, play button overlay on detected URLs.</li><li><strong>Privacy Policy</strong>: Published at docs site for Chrome Web Store compliance.</li></ul><h3 id="changed-2" tabindex="-1">Changed <a class="header-anchor" href="#changed-2" aria-label="Permalink to &quot;Changed&quot;">â€‹</a></h3><ul><li>Buffering state now stops presentation loop so frames accumulate for reliable recovery.</li><li>Buffering exit requires video frames ready (with 3s fallback for async decoder delays).</li><li>Pause during buffering allowed from all UI controls (click, keyboard, buttons, PiP, context menu).</li><li><code>buffering â†’ ended</code> state transition allowed for EOF during rebuffer.</li><li>Invalid packet size at EOF treated as EOF (not fatal error) for FFmpeg stale buffer data.</li><li>HDR icon changed to text badge style in OSD and context menu (matches bottom controls).</li><li>Extension description rewritten to remove excessive format keywords (Chrome Web Store compliance).</li><li>Console logs dropped in production build.</li></ul><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">â€‹</a></h3><ul><li>Hardware decoder error recovery with keyframe cache and software fallback.</li><li>Seek and play/pause during buffering state.</li><li>Network disconnect causing permanent CORS misclassification when <code>navigator.onLine</code> lags.</li><li>Stale stream loops from leaked online event listeners during backoff.</li><li>Multiple concurrent fetch loops after network recovery.</li><li>Clock advancing during buffering (presentation loop consuming frames).</li><li>PiP rotation clipping â€” rotation reset on PiP enter, restored on close.</li><li>PiP portrait video oversized â€” height-limited sizing for portrait aspect ratios.</li><li>Pause-seek loading stuck â€” <code>VideoDecoder.flush()</code> 1s timeout with reset+reconfigure fallback.</li><li>EOF not triggering â€” relaxed condition with 0.5s tolerance.</li><li>PiP canvas restore using <code>shadowRoot</code> directly.</li><li>PiP frame freeze on tab switch with <code>isPiPActive</code> guard.</li><li>EncryptedHttpSource network resilience matching HttpSource.</li><li>Nerd stats graph fullscreen positioning and CSS specificity.</li></ul><h2 id="_0-1-5-2026-02-15" tabindex="-1">[0.1.5] - 2026-02-15 <a class="header-anchor" href="#_0-1-5-2026-02-15" aria-label="Permalink to &quot;[0.1.5] - 2026-02-15&quot;">â€‹</a></h2><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">â€‹</a></h3><ul><li>Pitch preservation for playback rate changes</li><li>Pitch preservation support for HLS playback</li><li>MediaSession API integration for background playback and media controls</li><li>HTTPS support for local development environment</li></ul><h3 id="changed-3" tabindex="-1">Changed <a class="header-anchor" href="#changed-3" aria-label="Permalink to &quot;Changed&quot;">â€‹</a></h3><ul><li>Simplified error messages to be more concise and consistent</li><li>Replaced all hardcoded purple colors with CSS variables (--movi-primary) for full theme customization</li><li>Enhanced center play button with theme color by default</li><li>Updated loading spinner with responsive sizing and theme-aware colors</li></ul><h3 id="fixed-3" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-3" aria-label="Permalink to &quot;Fixed&quot;">â€‹</a></h3><ul><li>Improved playback stability with enhanced error handling and timeout management</li><li>Resolved audio-video sync issues with hardware decoding</li><li>Distinguished 403/401/404 errors from CORS errors for better error reporting</li><li>CORS errors now propagate immediately instead of waiting for timeout</li><li>Title bar z-index now properly positioned below control menus in mobile view</li><li>Center play button backdrop blur now enabled on mobile/touch devices</li><li>Controls no longer auto-hide when menus are open on mobile</li></ul><h2 id="_0-1-4-2026-02-11" tabindex="-1">[0.1.4] - 2026-02-11 <a class="header-anchor" href="#_0-1-4-2026-02-11" aria-label="Permalink to &quot;[0.1.4] - 2026-02-11&quot;">â€‹</a></h2><h3 id="fixed-4" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-4" aria-label="Permalink to &quot;Fixed&quot;">â€‹</a></h3><ul><li>Resolved video stalling during playback and improved A/V sync</li><li>Playback speed changes now take immediate effect on audio</li><li>Auto-unmute when volume slider is moved while muted</li><li>Mute button now correctly toggles audio muting</li></ul><h2 id="previous-versions" tabindex="-1">Previous Versions <a class="header-anchor" href="#previous-versions" aria-label="Permalink to &quot;Previous Versions&quot;">â€‹</a></h2><p>See git commit history for changes in versions prior to 0.1.4.</p>',39)])])}const p=o(a,[["render",n]]);export{g as __pageData,p as default};
